#include <stdio.h>

int main(void) {
    int values[100];
    size_t count;
    if (scanf("%zu", &count) != 1 || count > 100) return 1;
    for (size_t i = 0; i < count; ++i) if (scanf("%d", &values[i]) != 1) return 1;
    long long sum = 0;
    for (const int *cursor = values; cursor != values + count; ++cursor) sum += *cursor;
    printf("%lld\n", sum);
    return 0;
}
